#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <cuda_runtime.h>

#define TOL      (0.001)
#define STR_SIZE (256)
#define MAX_PD   (3.0e6)

#define PRECISION    0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI         100

#define FACTOR_CHIP	0.5

#define WG_SIZE_X (64)
#define WG_SIZE_Y (4)
float t_chip      = 0.0005;
float chip_height = 0.016;
float chip_width  = 0.016;
float amb_temp    = 80.0;

void usage(int argc, char **argv)
{
  fprintf(stderr, "Usage: %s <-n rows/cols> <-l layers> <-i iterations> <-f powerFile tempFile outputFile> [-p platform] [-d device]\n", argv[0]);
  fprintf(stderr, "\t<rows/cols>  - number of rows/cols in the grid (positive integer)\n");
  fprintf(stderr, "\t<layers>  - number of layers in the grid (positive integer)\n");

  fprintf(stderr, "\t<iteration> - number of iterations\n");
  fprintf(stderr, "\t<powerFile>  - name of the file containing the initial power values of each cell\n");
  fprintf(stderr, "\t<tempFile>  - name of the file containing the initial temperature values of each cell\n");
  fprintf(stderr, "\t<outputFile - output file\n");
  exit(1);
}

void readinput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {

    int i,j,k;
    FILE *fp;
    char str[STR_SIZE];
    float val;

    if( (fp  = fopen(file, "r" )) ==0 )
    {
      fprintf(stderr, "The file was not opened\n");
      exit(1);
    }

    for (i=0; i <= grid_rows-1; i++) 
      for (j=0; j <= grid_cols-1; j++)
        for (k=0; k <= layers-1; k++)
        {
            if (fgets(str, STR_SIZE, fp) == NULL) {
                fprintf(stderr, "Error reading file\n");
                exit(1);
            }
            if (feof(fp))
            {
                fprintf(stderr, "not enough lines in file\n");
                exit(1);
            }

            if ((sscanf(str, "%f", &val) != 1))
            {
                fprintf(stderr, "invalid file format\n");
                exit(1);
            }
            vect[i*grid_cols+j+k*grid_rows*grid_cols] = val;
        }

    fclose(fp);	

}

void writeoutput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {

    int i,j,k, index=0;
    FILE *fp;
    char str[STR_SIZE];

    if( (fp = fopen(file, "w" )) == 0 )
    {
      fprintf(stderr, "The file was not opened\n");
      return;
    }

    for (i=0; i < grid_rows; i++) 
      for (j=0; j < grid_cols; j++)
        for (k=0; k < layers; k++)
        {
            sprintf(str, "%d\t%g\n", index, vect[i*grid_cols+j+k*grid_rows*grid_cols]);
            fputs(str,fp);
            index++;
        }

    fclose(fp);	
}

void computeTempCPU(float *pIn, float* tIn, float *tOut, 
        int nx, int ny, int nz, float Cap, 
        float Rx, float Ry, float Rz, 
        float dt, float amb_temp, int numiter) 
{   float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw =stepDivCap/ Rx;
    cn = cs =stepDivCap/ Ry;
    ct = cb =stepDivCap/ Rz;

    cc = 1.0 - (2.0*ce + 2.0*cn + 3.0*ct);

    int c,w,e,n,s,b,t;
    int x,y,z;
    int i = 0;
    do{
        for(z = 0; z < nz; z++)
            for(y = 0; y < ny; y++)
                for(x = 0; x < nx; x++)
                {
                    c = x + y * nx + z * nx * ny;

                    w = (x == 0) ? c : c - 1;
                    e = (x == nx - 1) ? c : c + 1;
                    n = (y == 0) ? c : c - nx;
                    s = (y == ny - 1) ? c : c + nx;
                    b = (z == 0) ? c : c - nx * ny;
                    t = (z == nz - 1) ? c : c + nx * ny;

                    tOut[c] = tIn[c]*cc + tIn[n]*cn + tIn[s]*cs + tIn[e]*ce + tIn[w]*cw + tIn[t]*ct + tIn[b]*cb + (dt/Cap) * pIn[c] + ct*amb_temp;
                }
        float *temp = tIn;
        tIn = tOut;
        tOut = temp; 
        i++;
    }
    while(i < numiter);

}

float accuracy(float *arr1, float *arr2, int len)
{
    float err = 0.0; 
    int i;
    for(i = 0; i < len; i++)
    {
        err += (arr1[i]-arr2[i]) * (arr1[i]-arr2[i]);
    }

    return (float)sqrt(err/len);
}

__global__ void hotspotOpt1(float *p, float* tmp_17, float *x_2, float elem_16,
                            int x_4, int item_8, int data_7,
                            float item_1, float val_6, 
                            float var_9, float item_3,
                            float item_15, float elem_5, 
                            float x_11);

int main(int argc, char** argv)
{
    char *pfile = NULL, *tfile = NULL, *ofile = NULL;
    int iterations = 0;
    int numCols    = 0;
    int numRows    = 0;
    int layers     = 0;

    int cur_arg;
	for (cur_arg = 1; argc > cur_arg; cur_arg++) {
        if (0 == strcmp(argv[cur_arg], "-h")) {
			usage(argc, argv);
        }
        else if (0 == strcmp(argv[cur_arg], "-n")) {
            if (cur_arg + 1 <= argc) {
                numCols = numRows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (0 == strcmp(argv[cur_arg], "-l")) {
            if (cur_arg + 1 <= argc) {
                layers = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (0 == strcmp(argv[cur_arg], "-i")) {
            if (cur_arg + 1 <= argc) {
                iterations = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (0 == strcmp(argv[cur_arg], "-f")) {
            if (cur_arg + 3 <= argc) {
                pfile = argv[cur_arg+1];
                tfile = argv[cur_arg+2];
                ofile = argv[cur_arg+3];
                cur_arg = cur_arg + (3);
            }
        }
    }

	if (numCols == 0 || layers == 0 || iterations == 0 || pfile == NULL) {
		usage(argc, argv);
	}

  float dx         = chip_height/numRows;
  float dy         = chip_width/numCols;
  float dz         = t_chip/layers;

  float Cap        = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * dx * dy;
  float Rx         = dy / (2.0 * K_SI * t_chip * dx);
  float Ry         = dx / (2.0 * K_SI * t_chip * dy);
  float Rz         = dz / (K_SI * dx * dy);

  float max_slope  = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
  float dt         = PRECISION / max_slope;

  float ce, cw, cn, cs, ct, cb, cc;
  float stepDivCap = dt / Cap;
  ce               = cw                                              = stepDivCap/ Rx;
  cn               = cs                                              = stepDivCap/ Ry;
  ct               = cb                                              = stepDivCap/ Rz;

  cc               = 1.0 - (2.0*ce + 2.0*cn + 3.0*ct);

  int size = numCols * numRows * layers;
  float* tIn      = (float*) calloc(size,sizeof(float));
  float* pIn      = (float*) calloc(size,sizeof(float));
  float* tempCopy = (float*)malloc(size * sizeof(float));
  float* tempOut  = (float*) calloc(size,sizeof(float));
  if (!tIn || !pIn || !tempCopy || !tempOut) {
      fprintf(stderr, "Memory allocation failed\n");
      return 1;
  }
  readinput(tIn,numRows, numCols, layers, tfile);
  readinput(pIn,numRows, numCols, layers, pfile);

  memcpy(tempCopy,tIn, size * sizeof(float));

  float *d_tIn, *d_pIn, *d_tempOut;
  cudaError_t err;

  err = cudaMalloc((void**)&d_tIn, size * sizeof(float));
  if (err != cudaSuccess) { fprintf(stderr, "cudaMalloc d_tIn failed\n"); return 1; }
  err = cudaMalloc((void**)&d_pIn, size * sizeof(float));
  if (err != cudaSuccess) { fprintf(stderr, "cudaMalloc d_pIn failed\n"); return 1; }
  err = cudaMalloc((void**)&d_tempOut, size * sizeof(float));
  if (err != cudaSuccess) { fprintf(stderr, "cudaMalloc d_tempOut failed\n"); return 1; }

  err = cudaMemcpy(d_tIn, tIn, size * sizeof(float), cudaMemcpyHostToDevice);
  if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy d_tIn failed\n"); return 1; }
  err = cudaMemcpy(d_pIn, pIn, size * sizeof(float), cudaMemcpyHostToDevice);
  if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy d_pIn failed\n"); return 1; }
  err = cudaMemcpy(d_tempOut, tempOut, size * sizeof(float), cudaMemcpyHostToDevice);
  if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy d_tempOut failed\n"); return 1; }

  dim3 blockDim(WG_SIZE_X, WG_SIZE_Y);
  dim3 gridDim((numCols + WG_SIZE_X - 1) / WG_SIZE_X, (numRows + WG_SIZE_Y - 1) / WG_SIZE_Y);

  float elem_16 = stepDivCap;
  float item_1 = ce;
  float val_6 = cw;
  float var_9 = cn;
  float item_3 = cs;
  float item_15 = ct;
  float elem_5 = cc;
  float x_11 = cb;

  float *d_tmp_17 = d_tIn;
  float *d_x_2 = d_tempOut;

  for (int j = 0; j < iterations; j++) {
      hotspotOpt1<<<gridDim, blockDim>>>(d_pIn, d_tmp_17, d_x_2, elem_16,
                                        numCols, numRows, layers,
                                        item_1, val_6, var_9, item_3,
                                        item_15, elem_5, x_11);
      cudaDeviceSynchronize();

      float *tmp = d_tmp_17;
      d_tmp_17 = d_x_2;
      d_x_2 = tmp;
  }

  err = cudaMemcpy(tempOut, d_tmp_17, size * sizeof(float), cudaMemcpyDeviceToHost);
  if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy to host failed\n"); return 1; }

  float* answer = (float*)calloc(size, sizeof(float));
  if (!answer) {
      fprintf(stderr, "Memory allocation failed\n");
      return 1;
  }
  computeTempCPU(pIn, tempCopy, answer, numCols, numRows, layers, Cap, Rx, Ry, Rz, dt, amb_temp, iterations);
  float acc = accuracy(tempOut,answer,numRows*numCols*layers);
  printf("Accuracy: %e\n",acc);

  writeoutput(tempOut,numRows,numCols,layers,ofile);

  free(tIn);
  free(pIn);
  free(tempCopy);
  free(tempOut);
  free(answer);

  cudaFree(d_tIn);
  cudaFree(d_pIn);
  cudaFree(d_tempOut);

  return 0;
}
